div.script:
const input = document.getElementById("urlBar");
const iframe = document.getElementById("site");
const startScreen = document.getElementById("startScreen");

input.focus();

input.addEventListener("keydown", e=>{
    if(e.key==="Enter"){
        let url=input.value.trim();

        if(!/^https?:\/\//i.test(url)){
            url="https://"+url;
        }

        iframe.src=url;
        iframe.style.display="block";
        startScreen.style.display="none";
    }
});

// hey guys welcome back to another video
const bubble=document.getElementById("cameraBubble");
const video=bubble.querySelector("video");

navigator.mediaDevices?.getUserMedia({video:true})
.then(stream=>{
    video.srcObject=stream;
    bubble.style.display="block";
})
.catch(()=>{
    console.log("Camera permission denied.");
});

// drag
let dragging=false;
let offsetX=0;
let offsetY=0;

bubble.addEventListener("mousedown",e=>{
    dragging=true;
    bubble.style.cursor="grabbing";
    const rect=bubble.getBoundingClientRect();
    offsetX=e.clientX-rect.left;
    offsetY=e.clientY-rect.top;
});

document.addEventListener("mousemove",e=>{
    if(!dragging)return;

    bubble.style.left=(e.clientX-offsetX)+"px";
    bubble.style.top=(e.clientY-offsetY)+"px";
    bubble.style.right="auto";
});

document.addEventListener("mouseup",()=>{
    dragging=false;
    bubble.style.cursor="grab";
});

// alt + s
let visible=true;

document.addEventListener("keydown",e=>{
    if(e.altKey && e.key.toLowerCase()==="s"){
        e.preventDefault();
        visible=!visible;
        bubble.style.display=visible?"block":"none";
    }
});
